allowed = {"event_type", "username", "status"}

if group_field not in allowed:
    group_field = "event_type"

base = (
    "SELECT " + group_field + ", COUNT(*) "
    "FROM audit_events "
    "WHERE created_at >= %s AND created_at <= %s "
    "GROUP BY " + group_field + " "
    "ORDER BY COUNT(*) DESC"
)
